import SecureStorageService from './secureStorage.service';

const STORAGE_KEYS = {
  USER_PROFILE: '@secure_user_profile',
  PAYMENT_INFO: '@secure_payment_info',
  AUTH_TOKEN: '@secure_auth_token',
  REFRESH_TOKEN: '@secure_refresh_token',
};

class UserDataService {
  async saveUserProfile(profile) {
    if (!profile || typeof profile !== 'object') {
      throw new Error('Invalid user profile data');
    }
    await SecureStorageService.setItem(STORAGE_KEYS.USER_PROFILE, profile);
  }

  async getUserProfile() {
    return await SecureStorageService.getItem(STORAGE_KEYS.USER_PROFILE);
  }

  async savePaymentInfo(paymentInfo) {
    if (!paymentInfo || typeof paymentInfo !== 'object') {
      throw new Error('Invalid payment information');
    }
    await SecureStorageService.setItem(STORAGE_KEYS.PAYMENT_INFO, paymentInfo);
  }

  async getPaymentInfo() {
    return await SecureStorageService.getItem(STORAGE_KEYS.PAYMENT_INFO);
  }

  async saveAuthToken(token) {
    if (!token || typeof token !== 'string') {
      throw new Error('Invalid auth token');
    }
    await SecureStorageService.setItem(STORAGE_KEYS.AUTH_TOKEN, token);
  }

  async getAuthToken() {
    return await SecureStorageService.getItem(STORAGE_KEYS.AUTH_TOKEN);
  }

  async saveRefreshToken(token) {
    if (!token || typeof token !== 'string') {
      throw new Error('Invalid refresh token');
    }
    await SecureStorageService.setItem(STORAGE_KEYS.REFRESH_TOKEN, token);
  }

  async getRefreshToken() {
    return await SecureStorageService.getItem(STORAGE_KEYS.REFRESH_TOKEN);
  }

  async clearUserData() {
    await SecureStorageService.removeItem(STORAGE_KEYS.USER_PROFILE);
    await SecureStorageService.removeItem(STORAGE_KEYS.PAYMENT_INFO);
  }

  async clearAuthData() {
    await SecureStorageService.removeItem(STORAGE_KEYS.AUTH_TOKEN);
    await SecureStorageService.removeItem(STORAGE_KEYS.REFRESH_TOKEN);
  }

  async clearAllSecureData() {
    await this.clearUserData();
    await this.clearAuthData();
  }
}

export default new UserDataService();

